import React, { useState } from 'react';
import { Button, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd, formatDate, formatNumber } from '../../../utils/formatters';
import { exportExcel, MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import styles from '../../../styles/erpReportPage.module.css';

import type { ExpenseSummaryRow } from '../../../services/analytics/models';
const TABS = [{ value: 'month', label: 'Tháng' }, { value: 'quarter', label: 'Quý' }, { value: 'year', label: 'Năm' }];
const BaoCaoChiPhiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [tab, setTab] = useState('month');
  const [rows, setRows] = useState<ExpenseSummaryRow[]>([]);
  const [loading, setLoading] = useState(false);
  React.useEffect(() => { let c=false; setLoading(true); const t=setTimeout(()=>{ analyticsService.getExpenseSummary({ granularity: tab }).then(d=>{if(!c)setRows(d);}).catch(e=>{if(!c)dispatch(addToast({message:e?.message??'Lỗi',type:'error'}));}).finally(()=>{if(!c)setLoading(false);}); },0); return ()=>{c=true;clearTimeout(t);}; }, [tab,dispatch]);
  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}><div className={styles.titleBlock}><h1 className={styles.title}><i className="fas fa-receipt" /> Báo cáo chi phí</h1></div>
        <div className={styles.headerActions}><Button variant="secondary" onClick={()=>exportExcel('/accounting/reports/expense-summary/export-excel',{granularity:tab},`ChiPhi-${tab}.xlsx`)}><i className="fas fa-file-excel" /> Xuất Excel</Button></div></div>
      <div className={styles.tabs}>{TABS.map(t=>(<button key={t.value} type="button" className={tab===t.value?styles.tabActive:styles.tab} onClick={()=>setTab(t.value)}>{t.label}</button>))}</div>
      <div className={styles.tableCard}>{loading?<div className={styles.loading}><i className="fas fa-spinner fa-spin" /></div>:rows.length===0?<div className={styles.empty}><p>Không có dữ liệu</p></div>:<div className={styles.tableWrapper}><table className={styles.table}><thead><tr><th>Kỳ</th><th>Loại</th><th className={styles.colRight}>Chi phí</th></tr></thead><tbody>{rows.map((r,i)=>(<tr key={i}><td>{r.period}</td><td>{r.category??'—'}</td><td className={styles.colRight}>{formatVnd(r.expense)}</td></tr>))}</tbody></table></div>}</div>
    </div>
  );
};
export default BaoCaoChiPhiPage;
